-- ===============================================================
-- Idempotent UPSERT (MERGE) for RSMST_MSTPROCEDURES
-- Source: code_system_idrg_20260331.tsv (SAB=ICD9CM_2010_IM, 5,475 rows)
-- Match: proc_id = TSV.CODE (dotted, mis. 86.11)
--
-- WHEN MATCHED  : update HANYA valid_code/accpdx/asterisk/im
-- WHEN NOT MATCH: insert full row (proc_id, proc_desc, + 4 flag)
--
-- Prereq: 2026_05_20_alter_idrg_add_validation_columns.sql sudah dijalankan.
-- ===============================================================
SET DEFINE OFF;

MERGE INTO rsmst_mstprocedures d USING (SELECT '00' AS proc_id, 'Procedures and interventions, not elsewhere classified' AS proc_desc, 0 AS valid_code, 'N' AS accpdx, 0 AS asterisk, 0 AS im FROM dual) src ON (d.proc_id=src.proc_id) WHEN MATCHED THEN UPDATE SET d.valid_code=src.valid_code, d.accpdx=src.accpdx, d.asterisk=src.asterisk, d.im=src.im WHEN NOT MATCHED THEN INSERT (proc_id, proc_desc, valid_code, accpdx, asterisk, im) VALUES (src.proc_id, src.proc_desc, src.valid_code, src.accpdx, src.asterisk, src.im);
